   191→export function processPointsExtractData(
   192→  extractData: PointsExtractData | null | undefined,
   193→): ProcessedExtractData {
   194→  if (!extractData || typeof extractData !== 'object') {
   195→    return DEFAULT_PROCESSED_EXTRACT_DATA;
   196→  }
   197→
   198→  try {
   199→    const transactions = extractData.transactions || [];
   200→    const groupedTransactions = getGroupedTransactionsByDate(transactions);
   201→    const mappedTransactions = PointsDataGroupedByDayMapper.getMappedData(groupedTransactions);
   202→
   203→    return {
   204→      groupedTransactions,
   205→      mappedTransactions,
   206→    };
   207→  } catch (error) {
   208→    console.warn('Erro ao processar dados do extrato:', error);
   209→    return DEFAULT_PROCESSED_EXTRACT_DATA;
   210→  }
   211→}
   212→
   213→export function getPointsExtractFromResponse(
   214→  response: Awaited<ReturnType<typeof getPointsExtractApi>>,
   215→): PointsExtractData | null {
   216→  const apiResponse = response?.data;
   217→
   218→  if (!apiResponse) {
   219→    return null;
   220→  }
   221→
   222→  const status = apiResponse.status ?? (apiResponse as any).data?.status;
   223→  const returnCode = status?.returnCode;
   224→
   225→  const transactionsContainer = apiResponse.data ?? apiResponse;
   226→  const transactionsDto = transactionsContainer?.transactions;
   227→  const pagination = apiResponse.pagination ?? (apiResponse as any).data?.pagination;
   228→
   229→  if (!transactionsDto || !Array.isArray(transactionsDto)) {
   230→    return null;
   231→  } 
   232→
   233→  if (!pagination) {
   234→    return null;
   235→  }
   236→
   237→  const transactions = transactionsDto.map(getTransactionFromDto);
   238→
   239→  return {
   240→    transactions,
   241→    pagination,
   242→  };
   243→}
